{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires reconstructing a sequence of operations based on tree structures. This involves analyzing tree topology, identifying which nodes were merged, and determining the order of operations. I will split this into structural analysis, sequence validation, and final reconstruction.",
  "helpers": [
    {
      "label": "topology_analyzer",
      "instructions": "Analyze the initial tree and the final tree to identify the set of nodes that were merged. Specifically, identify which pairs of siblings in the initial tree were combined into a single node in the final tree. Map the parent-child relationships from the final tree back to the original nodes to determine which original subtrees were merged."
    },
    {
      "label": "dependency_solver",
      "instructions": "Given the set of merge operations identified by the topology analyzer, determine the valid temporal order of these operations. A merge operation on siblings can only occur if those siblings are currently children of the same parent and no other operations have altered their immediate parentage in a way that violates the tree structure. Identify any constraints on the order of merges (e.g., bottom-up vs top-down)."
    },
    {
      "label": "sequence_validator",
      "instructions": "Given a proposed sequence of merge operations, simulate the transformation from the initial tree to the final tree. Verify that each operation is valid at the time it is performed and that the resulting tree matches the target final tree exactly in terms of structure and node identity."
    }
  ],
  "synthesis_brief": "Combine the identified merge pairs from the topology analyzer with the temporal constraints from the dependency solver to construct a complete sequence. Use the sequence validator to ensure the proposed sequence is correct before finalizing the answer."
}

